import { spawn } from 'child_process';


export class ProcessResult {
	public code: number;
	public stdout: string;
	public stderr: string;
	public error: any;
}


export class TerminalUtils {

	/**
	 * Runs a terminal command
	 * @param {string} cmd Command to run
	 * @param {string[]} [args] Arguments to command
	 * @param {string} [cwd] Working directory to execute command
	 * @returns {Promise<T>}
	 */
	static async run(cmd: string, args?: string[], cwd?: string): Promise<ProcessResult> {
		return new Promise<ProcessResult>( (resolve, reject) => {
			let inst = cwd ? spawn(cmd, args, {cwd}) : spawn(cmd, args);
			let res = new ProcessResult();

			inst.stdout.on('data', (data:string) => {
				res.stdout = new Buffer(data).toString('utf8', 0);
			});

			inst.stderr.on('data', (data:string) => {
				res.stderr = new Buffer(data).toString('utf8', 0);
			});

			inst.on('error', (err) => {
				res.error = err;
				res.code = (err as any).code;
				reject(res);
			});

			inst.on('close', (code) => {
				res.code = code;
				if (code === 0) {
					resolve(res);
				}
				else {
					reject(res);
				}
			});
		});
	}

}

